command:
mkdir -p .claude-tdd-pro && printf 'sources: []
operator_namespace:
  - {id: a}
  - {id: b}
' > .claude-tdd-pro/PR-SOURCES.yaml && bash "$CLAUDE_PLUGIN_ROOT/commands/pr-source-add.sh" c/repo --gh-clone-stub stub --registry .claude-tdd-pro/PR-SOURCES.yaml 2>err.txt && bash "$CLAUDE_PLUGIN_ROOT/commands/pr-source-remove.sh" b --registry .claude-tdd-pro/PR-SOURCES.yaml --force 2>err.txt && grep -q 'a' .claude-tdd-pro/PR-SOURCES.yaml && grep -q 'c' .claude-tdd-pro/PR-SOURCES.yaml && ! grep -q 'b' .claude-tdd-pro/PR-SOURCES.yaml && echo ok 1>&2
